#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
#define int __int128
const int N=710,Mod=1e9+7;inline void DN(int &x){x>=Mod?x-=Mod:0;}
int a[N],n,dp[N][N][2],ans,Pw[N],Sm[N];
inline void print(int x){if(x>9)print(x/10);putchar(x%10+'0');}
inline void DP(int digit)
{
	memset(dp,0,sizeof(dp));
	rep(0,9,i)++dp[1][i>=digit][1];
	rep(0,a[1],i)++dp[1][i>=digit][0];
	rep(2,n,i)
	{
		rep(0,i,j)
		{
			if(j-1>=0)dp[i][j][1]+=dp[i-1][j-1][1]*(10-digit);
			dp[i][j][1]+=dp[i-1][j][1]*digit;
			if(j-(a[i]>=digit)>=0)dp[i][j][0]+=dp[i-1][j-(a[i]>=digit)][0];
			if(j-1>=0&&a[i]>digit)dp[i][j][0]+=dp[i-1][j-1][1]*(a[i]-digit);
			dp[i][j][0]+=dp[i-1][j][1]*min(a[i],digit);
			dp[i][j][0]%=Mod;dp[i][j][1]%=Mod;
		}
	}
