}
signed main()
{
	char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')a[++n]=(ch^48),ch=getchar();reverse(a+1,a+n+1);
	Sm[0]=1;Pw[0]=1;rep(1,n+2,i)Pw[i]=10ll*Pw[i-1]%Mod,DN(Sm[i]=Sm[i-1]+Pw[i]);
	rep(1,9,i){DP(i);rep(1,n,j)ans=(1ll*dp[n][j][0]*Sm[j-1]+ans)%Mod;}
	print(ans);return 0;
}
